8945 CmpInst::Predicate llvm::getMinMaxPred(SelectPatternFlavor SPF, bool Ordered) {
8946   if (SPF == SPF_SMIN) return ICmpInst::ICMP_SLT;
8947   if (SPF == SPF_UMIN) return ICmpInst::ICMP_ULT;
8948   if (SPF == SPF_SMAX) return ICmpInst::ICMP_SGT;
8949   if (SPF == SPF_UMAX) return ICmpInst::ICMP_UGT;
8950   if (SPF == SPF_FMINNUM)
