1371 /// Fold the following code sequence:
1372 /// \code
1373 ///   %XeqZ = icmp eq i64 %X, %Z
1374 ///   %YeqZ = icmp eq i64 %Y, %Z
1375 ///   %XeqY = icmp eq i64 %X, %Y
1376 ///   %not.YeqZ = xor i1 %YeqZ, true
1377 ///   %and = select i1 %not.YeqZ, i1 %XeqY, i1 false
1378 ///   %equal = select i1 %XeqZ, i1 %YeqZ, i1 %and
1379 /// \code
1380 ///
1381 /// into:
1382 ///   %equal = icmp eq i64 %X, %Y
